mapper.select:
/* com.educare.edu.comn.mapper.LectureStdntMapper.selectByParam */
select * from t_lecture_stdnt where edu_seq=#{eduSeq}
 and state = #{state}
 and user_id = #{userId}
order by user_nm

mapper.update:
/* com.educare.edu.comn.mapper.LectureStdntMapper.updateByPk */
	update t_lecture_stdnt
	set upd_de = #{updDe} , upd_id = #{updId}
	 		,state 		= #{state} 
	 	,rcept_seq 	= #{rceptSeq} 
	 	,dormi_fee 	= #{dormiFee} 
	where edu_seq=#{eduSeq} and user_id=#{userId}

/* com.educare.edu.comn.mapper.LectureStdntMapper.updatePassYn */
	update t_lecture_stdnt
	set pass_yn=#{passYn}
	where edu_seq=#{eduSeq} and user_id=#{userId}

mapper.select:
/* com.educare.edu.comn.mapper.LectureStdntMapper.selectPassUserIdCnt */
	select count(*) from t_lecture_stdnt where user_id = #{userId}
	and pass_yn = 'Y'
